# Module defining base classes using types from types_module

from types_module import Status, Point, IMeasurable

@abstract
class Shape(IMeasurable):
    position: Point

    def __init__(self, position: Point):
        self.position = position

    @virtual
    def desc(self) -> str:
        return "Shape"

    @abstract
    def area(self) -> float: ...

class Entity:
    status: Status

    def __init__(self, status: Status):
        self.status = status

