# Module with derived classes implementing interfaces and inheriting from base classes

from types_module import Point, IMeasurable
from base_module import Shape, Entity

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, position: Point, width: float, height: float):
        super().__init__(position)
        self.width = width
        self.height = height

    @override
    def desc(self) -> str:
        return f"Rectangle({self.width}, {self.height})"

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def get_status(self) -> str:
        return "Rectangle OK"

class Circle(Shape):
    radius: float

    def __init__(self, position: Point, radius: float):
        super().__init__(position)
        self.radius = radius

    @override
    def desc(self) -> str:
        return f"Circle({self.radius})"

    @override
    def area(self) -> float:
        PI: float = 3.14159
        return PI * self.radius * self.radius

    @override
    def get_status(self) -> str:
        return "Circle OK"

class Actor(Entity):
    def __init__(self, status: Status):
        super().__init__(status)

    def get_info(self) -> str:
        return f"Actor: {self.status.name}"
